//! Conformance tool definitions and dispatch.

use super::{ok, opt_str, req_str};
use lodestar_core::{ConformanceEvidence, Lodestar};
use serde_json::{json, Value};

pub(super) fn definitions() -> Vec<Value> {
    vec![
        json!({
            "name": "check_conformance",
            "description": "Evaluate a versioned, provenance-bearing ADR-0009 evidence bundle without changing task state.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "evidence": { "type": "object" },
                    "task_id": { "type": "string", "description": "Optional covering task." }
                },
                "required": ["evidence"]
            }
        }),
        json!({
            "name": "conformance_history",
            "description": "Retrieve the durable, append-only conformance evidence chain for a task: each record's stable id, the recorded evidence bundle, verdict, findings, and checked_at — the resolvable link proving how (and whether) a task reached completion.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "task_id": { "type": "string" }
                },
                "required": ["task_id"]
            }
        }),
    ]
}

pub(super) fn dispatch(
    engine: &Lodestar,
    name: &str,
    args: &Value,
) -> Option<Result<Value, String>> {
    match name {
        "check_conformance" => Some((|| {
            let evidence = parse_evidence(args)?;
            let result = engine
                .check_conformance(&evidence, opt_str(args, "task_id").as_deref())
                .map_err(|e| e.to_string())?;
            ok(&result)
        })()),
        "conformance_history" => Some((|| {
            ok(&engine
                .conformance_history(req_str(args, "task_id")?)
                .map_err(|e| e.to_string())?)
        })()),
        _ => None,
    }
}

pub(super) fn parse_evidence(args: &Value) -> Result<ConformanceEvidence, String> {
    let evidence = args
        .get("evidence")
        .cloned()
        .ok_or_else(|| "missing required object arg: evidence".to_string())?;
    serde_json::from_value(evidence).map_err(|error| format!("invalid evidence: {error}"))
}

#[cfg(test)]
mod tests {
    use super::super::call;
    use super::*;
    use lodestar_core::GoalKind;

    #[test]
    fn malformed_evidence_is_rejected_at_the_tool_boundary() {
        let engine = Lodestar::open_in_memory().unwrap();
        let params = json!({
            "name": "check_conformance",
            "arguments": { "evidence": { "schema_version": 1 } }
        });
        assert!(call(&engine, &params)
            .unwrap_err()
            .contains("invalid evidence"));
    }

    #[test]
    fn conformance_history_dispatch_returns_the_audit_chain() {
        let engine = Lodestar::open_in_memory().unwrap();
        let goal = engine
            .define_goal(GoalKind::Objective, "History", "prove it", None)
            .unwrap();
        let task = engine.create_task(&goal.id, "work", "done").unwrap();

        // No checks yet -> empty chain.
        let empty = call(
            &engine,
            &json!({ "name": "conformance_history", "arguments": { "task_id": task.id } }),
        )
        .unwrap();
        let records: Value =
            serde_json::from_str(empty["content"][0]["text"].as_str().unwrap()).unwrap();
        assert!(records.as_array().unwrap().is_empty());
    }
}
